#include <stdio.h>
#include <string.h>

const int MOD = 10000009;

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[1005];
    while(T--){
        scanf("%s",s);
        long long ans=1;
        int n=strlen(s);
        for(int i=0;i<n/2;i++){
            char a=s[i], b=s[n-1-i];
            if(a!='?' && b!='?'){
                if(a!=b){ ans=0; break; }
            }else if(a=='?' && b=='?'){
                ans = (ans*26)%MOD;
            }
        }
        if(ans!=0 && (n%2==1) && s[n/2]=='?') ans = (ans*26)%MOD;
        printf("%lld\n",ans);
    }
    return 0;
}

