code.Python3:
#!/usr/bin/env python3
import sys
MOD = 10000009

def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        s = data[i].strip()
        ans = 1
        n = len(s)
        for j in range(n//2):
            a, b = s[j], s[n-1-j]
            if a!='?' and b!='?':
                if a!=b:
                    ans = 0
                    break
            elif a=='?' and b=='?':
                ans = (ans*26) % MOD
        if ans!=0 and n%2==1 and s[n//2]=='?':
            ans = (ans*26) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

